def create_cluster_masks(image, z, filter, bcg_pos=None):
    """Create BCG, object and faint masks with default settings for Euclid data.

    These default settings are to be refined.
    """
    growth = 0.5
    regular_detection_params = None
    faint_detection_params = None
    sb_threshold = calc_sb_threshold(z, filter)
    sb_adu_threshold = sb_to_adu(
        sb_threshold, get_pixel_scale(image), image.header["MAGZERO"] * u.ABmag
    )
    bcg_mask = create_bcg_mask(
        image.data, sb_threshold=sb_adu_threshold, bcg_pos=bcg_pos, wcs=image.wcs
    )
    obj_mask, bkg, threshold = create_object_mask(
        image.data,
        bcg_mask=bcg_mask,
        growth=growth,
        detection_params=regular_detection_params,
    )
    faint_mask, faint_bkg, faint_threshold = create_faint_mask(
        image.data,
        object_mask=object_mask,
        bcg_mask=bcg_mask,
        growth=growth,
        detection_params=faint_detection_params,
    )
    return bcg_mask, obj_mask, faint_mask

# %% ../../nbs/euclid/mask.ipynb 7
def star_mask(bitmask, instrument, verbose=False):
    """Create a star mask from the DQ/FLG bitmask."""
    if verbose:
        print("Creating star mask")
    if instrument == "VIS":
        # use the STARSIGNAL flag
        mask = bitmask & 2**18 > 0
        erosion_radius = 20
        footprint = circular_footprint(radius=erosion_radius)
        mask = binary_erosion(mask, structure=footprint)
        growth_factor = 0.5
    else:
        # identify stars as saturated pixels that are not otherwise invalid (ignoring persistence)
        mask = bitmask & 2**10 > 0
        if verbose:
            print(f"Number of pixels with saturation masked: {mask.sum()}")
        for b in [2, 3, 4, 6, 7, 8, 9, 16, 23]:
            mask &= bitmask & 2**b == 0
            if verbose:
                print(f"Number of pixels masked after checking bitmask {b}: {mask.sum()}")
        growth_factor = 15
    min_pixels = 10
    star_mask = np.zeros(mask.shape, dtype=bool)
    if mask.sum() >= min_pixels:
        # segment the sources and dilate proportionally to the size of the source
        with catch_warnings():
            filterwarnings("ignore", ".*No sources were found*")
            star_segm = detect_sources(mask.astype(float), 0.5, npixels=min_pixels)
        if star_segm is not None:
            if verbose:
                print(f"Found {len(star_segm.segments)} stars")
            areas = np.unique(star_segm.areas)
            for area in areas:
                if verbose:
                    print(f"Masking stars with area {area}")
                idx = np.where(star_segm.areas == area)[0]
                labels = star_segm.labels[idx]
                segm = star_segm.copy()
                segm.keep_labels(labels)
                footprint = circular_footprint(radius=int(growth_factor * np.sqrt(area)))
                star_mask |= segm.make_source_mask(footprint=footprint)
    return star_mask

